62 |  * Mirrors StyleProfile v1.0 in api_contract.yaml.
63 |  * GET /api/authors/{author_id}/style-profile
64 |  */
65 | export interface StyleProfile {
66 |   /** Always "1.0" for this version of the schema. */
67 |   schema_version: "1.0";
68 |   /** Stable author identifier matching AuthorSummary.id. */
69 |   author_id: string;
70 |   /** ISO 8601 date-time when this profile was last computed. */
71 |   computed_at: string;
72 |   /** Corpus size statistics. */
73 |   corpus_stats: CorpusStats;
74 |   /** Lexical richness features. */
75 |   lexical: LexicalFeatures;
76 |   /** Syntactic complexity features. */
77 |   syntactic: SyntacticFeatures;
78 |   /** Stylistic / rhetorical features. */
79 |   stylistic: StylisticFeatures;
80 |   /** Top distinctive vocabulary items (TF-IDF ranked). Rendered as a top-10 table in the Style DNA panel. */
81 |   distinctive_vocab: DistinctiveTerm[];
82 |   /**
83 |    * 768-dimensional mean embedding vector.
84 |    * CONTRACT: Never send this array to any chart or client-rendered list —
85 |    * it is 768 floats and is not user-meaningful at the UI layer.
86 |    */
87 |   semantic_centroid: number[];
88 |   /** 2D UMAP projection of the cluster centroid and spread radius. */
89 |   embedding_umap_2d: EmbeddingUmap2d;
90 | }
