137 | /** Mirrors GenerateRequest in api_contract.yaml — body for POST /api/generate. */
138 | export interface GenerateRequest {
139 |   /** Target author voice (slug). */
140 |   author_id: string;
141 |   /** User creative prompt (English). Max 4000 chars per contract. */
142 |   prompt: string;
143 | }
144 | 
145 | /**
146 |  * Mirrors GenerateResponse in api_contract.yaml — 200 from POST /api/generate.
147 |  *
148 |  * NOTE (#19): PassportEnvelope is typed as `unknown` here — the Passport UI
149 |  * is out of scope for this issue. Full typing will be added in the Passport
150 |  * issue once the verify/display flow is built.
151 |  */
152 | export interface GenerateResponse {
153 |   vanilla: GenerationOutput;
154 |   autoria: GenerationOutput;
155 |   /** OUT OF SCOPE for #19 — typed as unknown; will be narrowed in the Passport issue. */
156 |   passport: unknown;
157 | }
