Contents of file frontend/src/components/GenerateStudio.tsx:

1 | "use client";
2 | 
3 | import { useCallback, useRef, useState } from "react";
4 | 
5 | import { PromptComposer } from "@/components/PromptComposer";
6 | import { SideBySideOutput } from "@/components/SideBySideOutput";
7 | import type { GenerationState } from "@/components/AuthorColumn";
8 | import { Button } from "@/components/ui/button";
9 | import { generateText } from "@/lib/api";
10 | import { en } from "@/lib/i18n/en";
11 | import type { AuthorCardData } from "@/lib/types";
12 | 
13 | interface GenerateStudioProps {
14 |   author: AuthorCardData;
15 | }
16 | 
17 | /**
18 |  * Generation studio client component — owns prompt state and both column
19 |  * GenerationStates. Passes real response data to SideBySideOutput; never
20 |  * fakes the contrast (design-system §8).
21 |  *
22 |  * The parent page (server component) owns the page header and data-voice.
23 |  * This component starts in an "idle" visual state before the first generation.
24 |  */
25 | export function GenerateStudio({ author }: GenerateStudioProps) {
26 |   const [prompt, setPrompt] = useState("");
27 |   const [isSubmitting, setIsSubmitting] = useState(false);
28 |   const [vanillaState, setVanillaState] = useState<GenerationState>({
29 |     status: "loading",
30 |   });
31 |   const [autoriaState, setAutoriaState] = useState<GenerationState>({
32 |     status: "loading",
33 |   });
34 |   const [hasGenerated, setHasGenerated] = useState(false);
35 | 
36 |   /**
37 |    * Passport from the most recent GenerateResponse.
38 |    * Remains `null` until the backend returns a non-null passport.
39 |    * Full handling (download / verify) deferred to #42 / #29.
40 |    */
41 |   const [passport, setPassport] = useState<unknown>(null);
42 | 
43 |   /**
44 |    * Distinctive terms from the StyleProfile — optional enhancement.
45 |    * Not fetched here; could be passed in from a parent that already has
46 |    * the StyleProfile loaded. Kept as a future prop without blocking
47 |    * generation (design-system §7, Deliverable 6).
48 |    */
49 |   const [distinctiveTerms] = useState<readonly string[]>([]);
50 | 
51 |   // Keep last prompt so onRetry can re-run it without re-reading stale state.
52 |   const lastPromptRef = useRef<string>("");
53 | 
54 |   const runGeneration = useCallback(
55 |     async (promptText: string) => {
56 |       lastPromptRef.current = promptText;
57 |       setIsSubmitting(true);
58 |       setHasGenerated(true);
59 |       setVanillaState({ status: "loading" });
60 |       setAutoriaState({ status: "loading" });
61 | 
62 |       try {
63 |         const response = await generateText(author.id, promptText);
64 |         setVanillaState({ status: "success", output: response.vanilla });
65 |         setAutoriaState({ status: "success", output: response.autoria });
66 |         // Store the passport from this generation; may be null if backend
67 |         // hasn't implemented signing yet (see backend #26).
68 |         setPassport(response.passport ?? null);
69 |       } catch (err: unknown) {
70 |         const isAbort = err instanceof Error && err.name === "AbortError";
71 |         const nextState: GenerationState = isAbort
72 |           ? { status: "timeout" }
73 |           : { status: "error" };
74 |         setVanillaState(nextState);
75 |         setAutoriaState(nextState);
76 |       } finally {
77 |         setIsSubmitting(false);
78 |       }
79 |     },
80 |     [author.id],
81 |   );
82 | 
83 |   const handleSubmit = useCallback(() => {
84 |     if (prompt.trim().length === 0 || isSubmitting) return;
85 |     void runGeneration(prompt);
86 |   }, [prompt, isSubmitting, runGeneration]);
87 | 
88 |   const handleRetry = useCallback(() => {
89 |     if (isSubmitting) return;
90 |     void runGeneration(lastPromptRef.current);
91 |   }, [isSubmitting, runGeneration]);
92 | 
93 |   const bothSucceeded =
94 |     vanillaState.status === "success" && autoriaState.status === "success";
95 | 
96 |   const handleGeneratePassport = useCallback(() => {
97 |     // TODO(#42): download formatted passport JSON
98 |   }, []);
99 | 
100 |   return (
101 |     <div className="flex flex-col gap-8">
102 |       {/* ── Section label ── */}
103 |       <p className="text-sm font-semibold uppercase tracking-wide text-muted-foreground">
104 |         {en.generate.sectionTitle}
105 |       </p>
106 | 
107 |       {/* ── Prompt composer ── */}
108 |       <section aria-label={en.generate.promptLabel}>
109 |         <PromptComposer
110 |           prompt={prompt}
111 |           isSubmitting={isSubmitting}
112 |           onPromptChange={setPrompt}
113 |           onSubmit={handleSubmit}
114 |         />
115 |       </section>
116 | 
117 |       {/* ── Side-by-side output ── */}
118 |       <section aria-label={en.generate.outputSectionLabel}>
119 |         {hasGenerated ? (
120 |           <SideBySideOutput
121 |             authorId={author.id}
122 |             authorName={author.name}
123 |             vanilla={vanillaState}
124 |             autoria={autoriaState}
125 |             distinctiveTerms={distinctiveTerms}
126 |             onRetry={handleRetry}
127 |           />
128 |         ) : (
129 |           <IdleState />
130 |         )}
131 |       </section>
132 | 
133 |       {/* ── Generate Passport button — only after first successful generation ── */}
134 |       {bothSucceeded && (
135 |         <div className="flex flex-col items-start gap-2">
136 |           <Button
137 |             variant="outline"
138 |             disabled={passport === null}
139 |             onClick={handleGeneratePassport}
140 |           >
141 |             {en.studio.passportButton}
142 |           </Button>
143 |           {passport === null && (
144 |             <p className="text-xs text-muted-foreground">
145 |               {en.studio.passportUnavailable}
146 |             </p>
147 |           )}
148 |         </div>
149 |       )}
150 |     </div>
151 |   );
152 | }
153 | 
154 | /**
155 |  * Placeholder shown before the first generation. Replaced by SideBySideOutput
156 |  * as soon as Generate is pressed for the first time.
157 |  */
158 | function IdleState() {
159 |   return (
160 |     <div className="grid grid-cols-1 gap-6 md:grid-cols-2">
161 |       {/* Instruction exposed once to assistive tech; the two cards below are
162 |           decorative placeholders (aria-hidden) to avoid a double announcement. */}
163 |       <p className="sr-only">{en.generate.idleBody}</p>
164 |       <IdleColumn />
165 |       <IdleColumn />
166 |     </div>
167 |   );
168 | }
169 | 
170 | function IdleColumn() {
171 |   return (
172 |     <div
173 |       className="flex min-h-[220px] flex-col items-center justify-center gap-3 rounded-xl border border-dashed border-border bg-card px-6 py-10 text-center shadow-paper-sm"
174 |       aria-hidden="true"
175 |     >
176 |       <p className="text-sm font-medium text-muted-foreground">
177 |         {en.generate.idleHeading}
178 |       </p>
179 |       <p className="max-w-[36ch] text-xs text-muted-foreground/70">
180 |         {en.generate.idleBody}
181 |       </p>
182 |     </div>
183 |   );
184 | }
185 |

