4 | // ---------------------------------------------------------------------------
5 | // Helper
6 | // ---------------------------------------------------------------------------
7 | 
8 | /** Round a number to n decimal places — mirrors the .toFixed() display path. */
9 | function r(n: number, places = 2): number {
10 |   return Math.round(n * 10 ** places) / 10 ** places;
11 | }
12 | 
13 | // ---------------------------------------------------------------------------
14 | // Edge cases: empty / whitespace
15 | // ---------------------------------------------------------------------------
16 | 
17 | describe("measureText — empty / whitespace input", () => {
18 |   it("returns all-zero struct for empty string", () => {
19 |     expect(measureText("")).toEqual({
20 |       wordCount: 0,
21 |       avgSentenceLength: 0,
22 |       ttr: 0,
23 |       topWords: [],
24 |     });
25 |   });
26 | 
27 |   it("returns all-zero struct for whitespace-only string", () => {
28 |     expect(measureText("   \n\t  ")).toEqual({
29 |       wordCount: 0,
30 |       avgSentenceLength: 0,
31 |       ttr: 0,
32 |       topWords: [],
33 |     });
34 |   });
35 | 
36 |   it("returns all-zero struct for punctuation-only string (no word chars)", () => {
37 |     const m = measureText("... ??? !!!");
38 |     expect(m.wordCount).toBe(0);
39 |     expect(m.ttr).toBe(0);
40 |     expect(m.topWords).toEqual([]);
41 |   });
42 | });
