48 | describe("measureText — wordCount", () => {
49 |   it("counts a simple sentence", () => {
50 |     expect(measureText("The cat sat on the mat.").wordCount).toBe(6);
51 |   });
52 | 
53 |   it("counts words separated by multiple spaces", () => {
54 |     expect(measureText("one  two   three").wordCount).toBe(3);
55 |   });
